import threading
from typing import Dict, List
from dataclasses import dataclass
from datetime import datetime

@dataclass
class Transaction:
    transaction_id: str
    account_id: str
    amount: float
    transaction_type: str  # 'debit' or 'credit'
    timestamp: datetime

class FinancialProcessor:
    def __init__(self):
        self.accounts: Dict[str, float] = {}
        self.transactions: List[Transaction] = []
        self._lock = threading.RLock()
    
    def process_transaction(self, transaction: Transaction) -> bool:
        with self._lock:
            # Validate transaction
            if not self._is_valid_transaction(transaction):
                return False
            
            # Process transaction
            if transaction.transaction_type == 'credit':
                self.accounts[transaction.account_id] = \
                    self.accounts.get(transaction.account_id, 0) + transaction.amount
            elif transaction.transaction_type == 'debit':
                current_balance = self.accounts.get(transaction.account_id, 0)
                if current_balance < transaction.amount:
                    return False  # Insufficient funds
                self.accounts[transaction.account_id] = current_balance - transaction.amount
            
            # Record transaction
            self.transactions.append(transaction)
            return True
    
    def _is_valid_transaction(self, transaction: Transaction) -> bool:
        return (transaction.account_id and 
                transaction.amount > 0 and 
                transaction.transaction_type in ['credit', 'debit'])
    
    def get_balance(self, account_id: str) -> float:
        with self._lock:
            return self.accounts.get(account_id, 0)
    
    def get_account_transactions(self, account_id: str) -> List[Transaction]:
        with self._lock:
            return [t for t in self.transactions if t.account_id == account_id]
    
    def batch_process(self, transactions: List[Transaction]) -> Dict[str, bool]:
        results = {}
        with self._lock:
            for transaction in transactions:
                results[transaction.transaction_id] = self.process_transaction(transaction)
        return results